#include <stdio.h>
#include <string.h>

#define N 1100000

int a[N];

int max(int x, int y) {
    return x > y ? x : y;
}

int perfect(int x) {
    int i;
    for (i = 0; i < 30; i++) {
        int num = 1 << i;
        if (num == x)
            return 1;
    }
    return 0;
}

int step(int x) {
    int i;
    for (i = 0; i < 30; i++) {
        int num = 1 << i;
        if (num >= x)
            return i;
    }
    return -1;
}

int main(int argc, char** argv) {
    int i, n, m, x, y, z, s;

    memset(a, 0, sizeof a);
    scanf("%d", &n);
    m = n;
    for (i = 2; i < N; i++) {
        while (n % i == 0) {
            n /= i;
            a[i]++;
        }
    }

    x = 1;
    y = 0;
    z = 0;
    s = 1;
    for (i = 2; i < N; i++)
        if (a[i] > 0) {
            x *= i;
            z = max(z, a[i]);
        }
    for (i = 2; i < N; i++)
        if (a[i] > 0 && a[i] != z)
            s = 0;

    if (s == 1 && perfect(z))
        y = step(z);
    else
        y = step(z) + 1;

    if (m == 1)
        puts("1 0");
    else
        printf("%d %d\n", x, y);

    return 0;
}

