use std::io;
use std::str;

pub struct Scanner<R> {
    reader: R,
    buffer: Vec<String>,
}

impl<R: io::BufRead> Scanner<R> {
    pub fn new(reader: R) -> Self {
        Self {
            reader,
            buffer: vec![],
        }
    }

    pub fn token<T: str::FromStr>(&mut self) -> T {
        loop {
            if let Some(token) = self.buffer.pop() {
                return token.parse().ok().expect("Failed parse");
            }
            let mut input = String::new();
            self.reader.read_line(&mut input).expect("Failed read");
            self.buffer = input.split_whitespace().rev().map(String::from).collect();
        }
    }
}

fn factorize(n: u64) -> Vec<(u64, u64)> {
    let mut n = n;
    let mut p = 2;
    let mut ans = Vec::new();
    while p * p <= n && n > 1 {
        let mut expo = 0;
        while n % p == 0 {
            expo += 1;
            n /= p;
        }
        if expo > 0 {
            ans.push((p, expo));
        }
        p += 1;
    }
    if n > 1{
        ans.push((n, 1));
    }
    ans
}

// fn is_power_of_two(n: u64) -> bool {
//     let expo = (n as f64).log2() as u32;
//     2u64.pow(expo) == n
// }

fn log2(n: u64) -> u64 {
    (n as f64).log2() as u64
}

fn find_min_ops(max_expo: u64, factors: &[(u64, u64)]) -> u64 {
    let m = max_expo.next_power_of_two();
    if m == max_expo {
        for (_, expo) in factors {
            if *expo < m {
                return 1 + log2(m);
            }
        }
        return log2(m);
    }
    1 + log2(m)
}

fn solve<R: io::BufRead, W: io::Write>(scan: &mut Scanner<R>, out: &mut W) {
    let n: u64 = scan.token();
    let factors = factorize(n);
    let mut min_n = 1;
    let mut max_expo = 1u64;
    for (p, expo) in &factors {
        min_n *= p;
        max_expo = max_expo.max(*expo);
    }
    if max_expo == 1 {
        writeln!(out, "{} 0", min_n).ok();
        return;
    }
    let min_ops = find_min_ops(max_expo, &factors);
    writeln!(out, "{} {}", min_n, min_ops).ok();
}

fn main() {
    let (stdin, stdout) = (io::stdin(), io::stdout());
    let mut scan = Scanner::new(stdin.lock());
    let mut out = io::BufWriter::new(stdout.lock());
    solve(&mut scan, &mut out);
}
